// Simple wrapper for executing raw SQL queries using Prisma
async function executeMCPQuery(query: string): Promise<string> {
  try {
    // Use Prisma's $queryRaw for executing raw SQL
    const result = await prisma.$queryRawUnsafe(query);

    // Return result as JSON string for consistency with existing code
    // Handle BigInt serialization by converting to string
    return JSON.stringify(
      result,
      (key, value) => (typeof value === "bigint" ? value.toString() : value),
      2,
    );
  } catch (error) {
    console.error("Database query failed:", error);
    throw error;
  }
}

