@Query(() => ReconciliationConnectionType)
async transactionReconciliation(
  @Args('filter', { nullable: true }) filter?: ReconciliationFilterInput,
  @Args('pagination', { nullable: true }) pagination?: ReconciliationPaginationInput,
): Promise<ReconciliationConnectionType> {
  const reconciliationFilter: ReconciliationFilter = {
    entityType: ['OwnershipTransaction', 'BusinessTransaction', 'GroupTransaction', 'OwnershipTransactionGroup'],
    ...filter,
  };

  const reconciliationPagination: ReconciliationPagination = {
    page: 1,
    limit: 50,
    sortBy: 'createdAt',
    sortOrder: 'desc',
    ...pagination,
  };

  const result = await this.reconciliationService.getReconciliationRecords(
    reconciliationFilter,
    reconciliationPagination,
  );

  return {
    edges: result.records.map(record => ({
      cursor: record.id,
      node: this.transformReconciliationRecord(record),
    })),
    pageInfo: {
      hasNextPage: result.hasNextPage,
      hasPreviousPage: result.hasPreviousPage,
      startCursor: result.records[0]?.id,
      endCursor: result.records[result.records.length - 1]?.id,
    },
    totalCount: result.totalCount,
  };
}

