/**
 * Process items in batches with controlled concurrency to avoid overwhelming APIs
 * @param items - Array of items to process
 * @param processor - Async function to process each item
 * @param batchSize - Number of concurrent operations (default: 50)
 * @param delayBetweenBatches - Delay in ms between batches (default: 50)
 * @returns Array of results in same order as input
 */
private async processInBatches<T, R>(
  items: T[],
  processor: (item: T) => Promise<R>,
  batchSize = 50,
  delayBetweenBatches = 50,
): Promise<R[]> {
  const results: R[] = [];
  const totalBatches = Math.ceil(items.length / batchSize);
  const startTime = Date.now();

  for (let i = 0; i < items.length; i += batchSize) {
    const batchNum = Math.floor(i / batchSize) + 1;
    const batch = items.slice(i, i + batchSize);
    const batchResults = await Promise.all(batch.map(processor));
    results.push(...batchResults);

    // Log progress every 10 batches or on last batch
    if (batchNum % 10 === 0 || batchNum === totalBatches) {
      const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
      const pct = ((results.length / items.length) * 100).toFixed(0);
      console.log(
        `Embedding progress: ${results.length}/${items.length} (${pct}%) - batch ${batchNum}/${totalBatches} - ${elapsed}s elapsed`,
      );
    }

    // Add delay between batches to avoid rate limiting
    if (i + batchSize < items.length && delayBetweenBatches > 0) {
      await new Promise((resolve) => setTimeout(resolve, delayBetweenBatches));
    }
  }

  return results;
}

