/**
 * Update an existing customer logo
 */
@Mutation(() => CustomerLogoDto)
async updateCustomerLogo(
  @Args("id", { type: () => ID }) id: string,
  @Args("input") input: UpdateCustomerLogoInput,
): Promise<CustomerLogoDto> {
  this.logger.info(`Updating logo ${id}`);

  const logo = await this.logoService.updateLogo(id, {
    name: input.name,
    description: input.description,
    dataBase64: input.dataBase64,
    isActive: input.isActive,
    isCurrent: input.isCurrent,
  });

  // Trigger sync if already synced
  if (logo.backendId) {
    await this.syncService.syncUpdateLogo(id, !!input.dataBase64);
  }

  return this.mapToDto(logo);
}

/**
 * Delete a customer logo (soft delete)
 */
@Mutation(() => Boolean)
async deleteCustomerLogo(
  @Args("id", { type: () => ID }) id: string,
): Promise<boolean> {
  this.logger.info(`Deleting logo ${id}`);

  const logo = await this.logoService.deleteLogo(id);

  // Trigger sync deletion if synced
  if (logo.backendId) {
    await this.syncService.syncDeleteLogo(id);
  }

  return true;
}

