@Mutation(() => Boolean)
async rejectRequest(
  @Args('input') input: RejectionInput,
  @UserData() user: any,
): Promise<boolean> {
  const result = await this.approvalWorkflowService.rejectRequest(
    input.requestId,
    user.username,
    input.reason,
    input.suggestions,
  );

  // Publish to subscriptions
  pubSub.publish('APPROVAL_UPDATED', {
    approvalUpdates: {
      type: 'REJECTED',
      requestId: input.requestId,
      data: { rejectedBy: user.username, reason: input.reason },
    },
  } as any);

  return result.success;
}

@Mutation(() => Boolean)
async addApprovalComment(
  @Args('input') input: ApprovalCommentInput,
  @UserData() user: any,
): Promise<boolean> {
  const result = await this.approvalWorkflowService.addComment(
    input.requestId,
    user.username,
    input.content,
    input.type,
  );

  return result.success;
}

