/**
 * Sanitize query parameters to prevent PII leakage in logs.
 * Redacts all parameter values while preserving structure for debugging.
 * @param params Raw params string from Prisma query event
 * @returns Sanitized params string or "[REDACTED]" on failure
 */
function sanitizeParams(params: string): string {
  try {
    const parsed = JSON.parse(params);
    if (Array.isArray(parsed)) {
      return `[${parsed.length} parameters]`;
    }
    return "[REDACTED]";
  } catch {
    return "[REDACTED]";
  }
}

