/**
 * Daily cleanup of failed jobs older than 7 days
 * Keeps failed jobs longer for debugging purposes
 */
@Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
async cleanupFailedJobs(): Promise<void> {
  this.logger.debug("🧹 Starting daily cleanup of old failed jobs");

  try {
    const cutoffTime =
      Date.now() - this.FAILED_JOBS_RETENTION_DAYS * 24 * 60 * 60 * 1000;

    // Get failed jobs older than cutoff
    const failedJobs = await this.inventoryQueue.getFailed(
      0,
      this.MAX_JOBS_TO_SCAN,
    );
    const jobsToRemove = failedJobs.filter((job) => {
      const failedTime = job.failedReason
        ? job.processedOn || job.timestamp
        : 0;
      return failedTime > 0 && failedTime < cutoffTime;
    });

    // Remove old failed jobs in batches
    let removedCount = 0;
    for (const job of jobsToRemove) {
      try {
        await job.remove();
        removedCount++;
      } catch (error) {
        this.logger.warn(
          `Failed to remove failed job ${job.id}:`,
          error instanceof Error ? error.message : String(error),
        );
      }
    }

    if (removedCount > 0) {
      this.logger.log(
        `✅ Daily cleanup completed: removed ${removedCount} failed jobs older than ${this.FAILED_JOBS_RETENTION_DAYS} days`,
      );
    } else {
      this.logger.debug(
        "✅ Daily cleanup completed: no old failed jobs to remove",
      );
    }
  } catch (error) {
    this.logger.error("❌ Failed to cleanup failed jobs:", error);
  }
}

