private mapInventorySourceTypeToPrisma(
  sourceType: InventorySourceType,
): FinancialTransactionSource {
  switch (sourceType) {
    case InventorySourceType.OWNERSHIP_TRANSACTION:
      return FinancialTransactionSource.OWNERSHIP_TRANSACTION;
    case InventorySourceType.TRANSFER_EVENT:
      return FinancialTransactionSource.TRANSFER_EVENT;
    case InventorySourceType.MANUAL_ADJUSTMENT:
      return FinancialTransactionSource.MANUAL_ADJUSTMENT;
    case InventorySourceType.PHYSICAL_COUNT:
      return FinancialTransactionSource.PHYSICAL_COUNT;
    case InventorySourceType.SYSTEM_CORRECTION:
      return FinancialTransactionSource.SYSTEM_CORRECTION;
    case InventorySourceType.DAMAGE_WRITE_OFF:
      return FinancialTransactionSource.DAMAGE_WRITE_OFF;
    case InventorySourceType.FOUND_INVENTORY:
      return FinancialTransactionSource.FOUND_INVENTORY;
    case InventorySourceType.ROLLBACK:
      return FinancialTransactionSource.ROLLBACK;
    case InventorySourceType.RECONCILIATION:
      return FinancialTransactionSource.RECONCILIATION;
    default:
      throw new BadRequestException(
        `Unknown inventory source type: ${sourceType}`,
      );
  }
}

