    const sequenceNum = Number.parseInt(sequencePart, 10);
    if (!Number.isNaN(sequenceNum) && sequenceNum > maxSequence) {
      maxSequence = sequenceNum;
    }
  });

  // Generate next sequence number with zero padding (2 digits)
  const nextSequence = maxSequence + 1;
  const paddedSequence = nextSequence.toString().padStart(2, "0");

  return `${prefix}${paddedSequence}`;
}

