/**
 * Normalize URL-safe base64 to standard base64 format
 * Converts '-' to '+', '_' to '/', and adds padding if needed
 */
private normalizeBase64(dataBase64: string): string {
  // Replace URL-safe characters with standard base64 characters
  let normalized = dataBase64.replace(/-/g, "+").replace(/_/g, "/");

  // Add padding if needed (base64 length must be multiple of 4)
  const paddingNeeded = (4 - (normalized.length % 4)) % 4;
  if (paddingNeeded > 0) {
    normalized += "=".repeat(paddingNeeded);
  }

  return normalized;
}

