  stagingId: string,
  reviewedBy: string,
  rejectionReason: string,
): Promise<void> {
  this.logger.log(`Rejecting single staging record ${stagingId}`);

  await this.prisma.inventoryCheckStaging.update({
    where: { id: stagingId },
    data: {
      processingStatus: InventoryCheckStagingStatus.REJECTED,
      reviewedBy,
      reviewedAt: new Date(),
      approvalDecision: ApprovalDecision.REJECTED,
      rejectionReason,
    },
  });
}

