    `Creating logo "${input.name}" for customer ${input.customerId}`,
  );

  const logo = await this.logoService.createLogo({
    customerId: input.customerId,
    name: input.name,
    description: input.description,
    filename: input.filename,
    dataBase64: input.dataBase64,
    mimeType: input.mimeType,
    isCurrent: input.isCurrent,
  });

  // Trigger sync to backend
  await this.syncService.syncCreateLogo(logo.id);

  return this.mapToDto(logo);
}

