): Promise<CustomerLogoDto> {
  this.logger.info(`Updating logo ${id}`);

  const logo = await this.logoService.updateLogo(id, {
    name: input.name,
    description: input.description,
    dataBase64: input.dataBase64,
    isActive: input.isActive,
    isCurrent: input.isCurrent,
  });

  // Trigger sync if already synced
  if (logo.backendId) {
    await this.syncService.syncUpdateLogo(id, !!input.dataBase64);
  }

  return this.mapToDto(logo);
}

