/**
 * Migrate BarrelOwnership records with conflict handling
 * Handles both unique constraint conflicts and active ownership constraints
 *
 * @param preserveOldBarrel - When true, end old ownership records instead of deleting them
 */
async function migrateBarrelOwnerships(
  prisma: Prisma.TransactionClient,
  oldBarrelId: string,
  newBarrelId: string,
  preserveOldBarrel: boolean,
  logger?: Logger,
): Promise<number> {
  logger?.log(
    `Migrating BarrelOwnership records from ${oldBarrelId} to ${newBarrelId} (preserveOldBarrel: ${preserveOldBarrel})`,
  );

  // Fetch all ownership records for the old barrel
  const existingOwnerships = await prisma.barrelOwnership.findMany({
    where: { barrelId: oldBarrelId },
  });

  // Check if new barrel has any active ownership records (validTo IS NULL AND validFrom <= CURRENT_DATE)
  // This is important because the database has a constraint preventing multiple active ownerships
  const newBarrelActiveOwnerships = await prisma.barrelOwnership.findMany({
    where: {
      barrelId: newBarrelId,
      validTo: null,
      validFrom: {
        lte: new Date(),
      },
    },
  });

  // Track if we've migrated an active ownership to prevent multiple active ownerships
  let hasActiveOwnershipOnTarget = newBarrelActiveOwnerships.length > 0;
  let migratedCount = 0;

  for (const ownership of existingOwnerships) {
    // Check for unique constraint conflict
    const conflict = await prisma.barrelOwnership.findUnique({
      where: {
        barrelId_customerId_validFrom: {
          barrelId: newBarrelId,
          customerId: ownership.customerId,

    }

    // Perform actual cleanup in transaction
    const errors: string[] = [];
    let actualSessionsDeleted = 0;
    let actualStagingDeleted = 0;

    for (const sessionId of sessionIds) {
      try {
        await this.prisma.$transaction(async (tx) => {
          // Delete staging records first (due to foreign key constraints)
          const stagingDeleteResult =
            await tx.inventoryUploadStaging.deleteMany({
              where: { uploadSessionId: sessionId },
            });

          // Delete the session
          await tx.inventoryUploadSession.delete({
            where: { id: sessionId },
          });

          actualSessionsDeleted++;
          actualStagingDeleted += stagingDeleteResult.count;
        });
      } catch (error) {
        const errorMessage = `Failed to delete session ${sessionId}: ${error instanceof Error ? error.message : "Unknown error"}`;
        this.logger.error(errorMessage);
        errors.push(errorMessage);
      }
    }

    const operationDurationMs = Date.now() - startTime;

    const result: CleanupResultDto = {
      sessionsDeleted: actualSessionsDeleted,
      stagingRecordsDeleted: actualStagingDeleted,
      storageFreedBytes: actualStagingDeleted * 1024, // Rough estimate
      operationDurationMs,
      cleanupTimestamp: new Date(),
      deletedSessionIds: sessionIds.slice(0, actualSessionsDeleted),
      errors: errors.length > 0 ? errors : undefined,
    };

    this.logger.info(`Cleanup completed`, result);
    return result;
  } catch (error) {
    this.logger.error(
      `Failed to cleanup old sessions: ${error instanceof Error ? error.message : "Unknown error"}`,
    );
    throw new BadRequestException(
      `Failed to cleanup old sessions: ${error instanceof Error ? error.message : "Unknown error"}`,
    );
  }
}

