  if (file.size > this.maxFileSize) {
    errors.push(
      `File size ${(file.size / 1024 / 1024).toFixed(2)}MB exceeds maximum allowed size of ${this.maxFileSize / 1024 / 1024}MB`,
    );
  }

  // Check MIME type
  if (!this.allowedMimeTypes.includes(file.mimetype)) {
    errors.push(
      `File type ${file.mimetype} is not supported. Allowed types: ${this.allowedMimeTypes.join(", ")}`,
    );
  }

  // Check file extension
  const fileExtension = path.extname(file.originalname).toLowerCase();
  if (![".csv", ".txt", ".xls", ".xlsx"].includes(fileExtension)) {
    errors.push(
      `File extension ${fileExtension} is not supported. Allowed extensions: .csv, .txt, .xls, .xlsx`,
    );
  }

  // For CSV files, validate headers and basic structure
