  documents: Array<{
    content: string;
    metadata?: Record<string, any>;
  }>,
  namespace?: string,
): Promise<string[]> {
  try {
    // Generate embeddings in batches to avoid overwhelming OpenAI API
    const BATCH_SIZE = 50;
    const BATCH_DELAY_MS = 50;
    console.log(
      `Generating embeddings for ${documents.length} documents (batch size: ${BATCH_SIZE})...`,
    );
    const embeddings = await this.processInBatches(
      documents,
      (doc) => this.getOrCreateEmbedding(doc.content),
      BATCH_SIZE,
      BATCH_DELAY_MS,
    );

    // Prepare data for batch insert
    const documentsData = documents.map((doc, index) => ({
      content: doc.content,
      metadata: {
        ...doc.metadata,
        ...(namespace && { namespace }),
      },
      embedding: embeddings[index],
      identityKey: `batch|${Date.now()}|${index}|${crypto.randomUUID()}`,
    }));

    // Batch insert using createMany
    const result = await this.prisma.vectorDocument.createMany({
      data: documentsData,
    });

    console.log(
      `✓ Stored ${result.count} documents in batch to vector database`,
    );

    // Since createMany doesn't return IDs, we need to fetch them
    const keys = documentsData.map((d) => d.identityKey);
    const createdDocuments = await this.prisma.vectorDocument.findMany({
      where: { identityKey: { in: keys } },
      select: { id: true, identityKey: true },
    });

    return createdDocuments.map((doc) => doc.id);
  } catch (error) {
    console.error("Error storing documents in batch:", error);
    throw error;
  }
}

